const fs = require('fs');
const path = require('path');

const files = {
  "src/app/privacy/page.tsx": ``,
  "src/app/terms/page.tsx": ``,
};

Object.entries(files).forEach(([filePath, b64]) => {
  const fullPath = path.join(process.cwd(), filePath);
  const dir = path.dirname(fullPath);
  fs.mkdirSync(dir, { recursive: true });
  const content = Buffer.from(b64, 'base64').toString('utf-8');
  fs.writeFileSync(fullPath, content, 'utf-8');
  console.log('Wrote:', filePath);
});

console.log('\n✅ Patch v20 applied — Privacy Policy + Terms of Service pages');
console.log('\nNew pages:');
console.log('  /privacy — Full privacy policy with state-by-state rights');
console.log('  /terms   — Complete terms of service');
